function validate(args, output) {
    const words = args[0], groups = args[1];
    const n = words.length;
    if (!Array.isArray(output) || output.length === 0 || !output.every(w => typeof w === 'string')) return false;
    const indexOf = new Map(words.map((w, i) => [w, i]));
    const idxs = [];
    for (const w of output) {
        if (!indexOf.has(w)) return false;
        idxs.push(indexOf.get(w));
    }

    function hammingOne(a, b) {
        if (a.length !== b.length) return false;
        let diff = 0;
        for (let k = 0; k < a.length; k++) {
            if (a[k] !== b[k]) {
                diff++;
                if (diff > 1) return false;
            }
        }
        return diff === 1;
    }

    for (let k = 0; k + 1 < idxs.length; k++) {
        if (idxs[k + 1] <= idxs[k]) return false;
        if (groups[idxs[k]] === groups[idxs[k + 1]]) return false;
        if (!hammingOne(words[idxs[k]], words[idxs[k + 1]])) return false;
    }

    const dp = new Array(n).fill(1);
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < i; j++) {
            if (groups[j] === groups[i]) continue;
            if (!hammingOne(words[j], words[i])) continue;
            if (dp[j] + 1 > dp[i]) dp[i] = dp[j] + 1;
        }
    }
    return output.length === Math.max(...dp);
}

