class Solution:
    def getWordsInLongestSubsequence(self, words, groups):
        def hamming_one(a, b):
            if len(a) != len(b):
                return False
            diff = 0
            for x, y in zip(a, b):
                if x != y:
                    diff += 1
                    if diff > 1:
                        return False
            return diff == 1

        n = len(words)
        dp = [1] * n
        parent = [-1] * n
        best_end = 0
        for i in range(n):
            for j in range(i):
                if groups[j] == groups[i]:
                    continue
                if not hamming_one(words[j], words[i]):
                    continue
                if dp[j] + 1 > dp[i]:
                    dp[i] = dp[j] + 1
                    parent[i] = j
            if dp[i] > dp[best_end]:
                best_end = i
        idx = []
        cur = best_end
        while cur != -1:
            idx.append(cur)
            cur = parent[cur]
        idx.reverse()
        return [words[i] for i in idx]

