var getWordsInLongestSubsequence = function(words, groups) {
    function hammingOne(a, b) {
        if (a.length !== b.length) return false;
        let diff = 0;
        for (let k = 0; k < a.length; k++) {
            if (a[k] !== b[k]) {
                diff++;
                if (diff > 1) return false;
            }
        }
        return diff === 1;
    }

    const n = words.length;
    const dp = new Array(n).fill(1);
    const parent = new Array(n).fill(-1);
    let bestEnd = 0;
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < i; j++) {
            if (groups[j] === groups[i]) continue;
            if (!hammingOne(words[j], words[i])) continue;
            if (dp[j] + 1 > dp[i]) {
                dp[i] = dp[j] + 1;
                parent[i] = j;
            }
        }
        if (dp[i] > dp[bestEnd]) bestEnd = i;
    }
    const idx = [];
    let cur = bestEnd;
    while (cur !== -1) {
        idx.push(cur);
        cur = parent[cur];
    }
    idx.reverse();
    return idx.map(i => words[i]);
};
